- (WBVAppModel *)parseVAppHttpModel:(WBVAppBaseHttpModel *)vapp {
    WBVAppModel *current = _allApps[vapp.bundle_id];
    if (current == nil) {
        current = [WBVAppModel initWithVAppBaseModel:vapp];
        _allApps[vapp.bundle_id] = current;
    } else if (vapp.scheme != nil && current.scheme == nil) {
        // merge the scheme field, for local WBVappScheme.plist datas
        current.scheme = vapp.scheme;
    } else if (vapp.reserve_count > current.reserveCount) {
        // update with the maximum
        current.reserveCount = vapp.reserve_count;
    }
    current.visible = vapp.visible;

    return current;
}

- (NSMutableArray<WBVAppModel *> *)parseVAppHttpModelList:(NSArray<WBVAppBaseHttpModel *> *)vapps {
    NSMutableArray<WBVAppModel*> *list = [[NSMutableArray alloc] init];
    for(WBVAppBaseHttpModel* vapp in vapps) {
        WBVAppModel *parsedVapp = [self parseVAppHttpModel:vapp];
        [list addObject:parsedVapp];
    }
    return list;
}

