//
// migrate old app data to new app data, run it in a non-main thread if the migration might take a long time in the future
//
- (void)fileSystemVersionCheck {
    NSInteger currentVersion = WBSettingManager.sharedManager.FileSystemVersion;
    if (currentVersion == fileSystemVersionEmpty) {
        // its a fresh installation OR its an old filesystem with no filesystem version number
        //
        // we identify old filesystem by the existense of file "wb_vapp_status.plist"
        NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
        if ([NSFileManager.defaultManager fileExistsAtPath:oldInstalledVAppListFilePath]) {
            currentVersion = fileSystemVersionClassic;
        }
    }
    if (currentVersion != kNewestFileSystemVersion) {
        [self migrateFrom:currentVersion to:kNewestFileSystemVersion];
        WBSettingManager.sharedManager.FileSystemVersion = kNewestFileSystemVersion;
    }
}


- (void)migrateFrom:(NSInteger)from to:(NSInteger)to{
    while(from != to) {
        switch(from) {
            case fileSystemVersionEmpty:
                return;
            case fileSystemVersionClassic:
                from = [self migrateFromClassicToStorageManager];
            case fileSystemVersionWithStorageManager:
                return;
            default:
                NSAssert(false, @"invalid file system version");
                return;
        }
    }
}
- (NSInteger)migrateFromClassicToStorageManager {
    //
    // wb_vapp_status.plist
    //
    NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
    NSArray *jsonArray = [NSArray arrayWithContentsOfFile:oldInstalledVAppListFilePath];
    NSMutableArray *newJsonArray = [[NSMutableArray alloc] init];
    for(NSDictionary* dic in jsonArray) {
        NSMutableDictionary *newObj = [[NSMutableDictionary alloc] init];
        newObj[@"vid"] = dic[@"id"];
        newObj[@"name"] = dic[@"name"];
        newObj[@"trackId"] = nil;
        newObj[@"bundleId"] = dic[@"bundle_id"];
        newObj[@"iconURL"] = dic[@"icon_url"];
        newObj[@"subtitle"] = nil;
