    if (self = [super init]) {
        self.autoLockDuration = 0;
    }
    return self;
}

+ (instancetype)initWithVAppBaseModel:(WBVAppBaseHttpModel*)model {
    WBVAppModel *instance = [[WBVAppModel alloc] init];
    instance.vid = model.vid;
    instance.name = model.name;
    instance.trackId = model.track_id;
    instance.bundleId = model.bundle_id;
    instance.iconURL = model.icon_url;
    instance.subtitle = model.subtitle;
    instance.artistName = model.artist_name;
    instance.scheme = model.scheme;
    instance.reserveCount = model.reserve_count;
    instance.visible = model.visible;
//    instance.status = WBVappStatusNone;
    return instance;
}

+ (instancetype)initWithVAppDetailModel:(WBVAppDetailHttpModel *)model {
    WBVAppModel *instance = [self initWithVAppBaseModel:model];
    [instance updateWithVAppDetailModel:model];
    return instance;
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (NSString *)getDisplayName {
    if (_userInfo && _userInfo.customName && (WBSettingManager.sharedManager.IsVIP || WBSettingManager.sharedManager.IsSVIP)) {
        return _userInfo.customName;
    } else {
        return _name;
    }
}

- (NSURL *)getDisplayIconURL {
    if (_userInfo && _userInfo.customIcon && (WBSettingManager.sharedManager.IsVIP || WBSettingManager.sharedManager.IsSVIP)) {
        return [NSURL URLWithString:_userInfo.customIcon];
    } else {
        return [NSURL URLWithString:_iconURL];
    }
}

- (void)updateWithVAppDetailModel:(WBVAppDetailHttpModel*)model {
    WBVAppVersionInfo *versionInfo = [WBVAppVersionInfo initWithVAppDetailModel:model];
    versionInfo.prevVersion = self.versionInfo.version;
    self.versionInfo = versionInfo;

    // Record current osVersion and engineVersion
    WBVAppLaunchInfo *launchInfo = [[WBVAppLaunchInfo alloc] init];
    launchInfo.osVersion = [WBQuery query].osVersion;
    launchInfo.engineVersion = [WBQuery query].engineVersion;
    self.launchInfo = launchInfo;

    // Init vapp error info
    WBVAppErrorInfo *errorInfo = [[WBVAppErrorInfo alloc] init];
    errorInfo.errorType = WBVappStatusNone;
    errorInfo.errorDomain = @"";
    errorInfo.errorCode = 0;
    errorInfo.errorMessage = @"";
    self.errorInfo = errorInfo;

    // Init vapp features switch status
    WBVAppFeatureStatus *featureStatusInfo = [[WBVAppFeatureStatus alloc] init];
    featureStatusInfo.isLockSwitchOn = NO;
    featureStatusInfo.isNotificationSwitchOn = NO;
    featureStatusInfo.isDisguiseSwitchOn = NO;
    featureStatusInfo.isPretenseSwitchOn = NO;
    featureStatusInfo.isOneClickSwitchOn = NO;
    self.featureStatusInfo = featureStatusInfo;
}

- (void)setInMemoryStatus:(WBVappStatus)status {
    if (status & (WBVappStatusWaitingDownload | WBVappStatusDownloadError | WBVappStatusInstallError | WBVappStatusResourceDownloadError | WBVappStatusResourceInstallError)) {
        _progress = 0.0;
    } else if (status & (WBVappStatusDownloaded | WBVappStatusInstalled | WBVappStatusResourceDownloaded | WBVappStatusResourceInstalled)) {
        _progress = 1.0f;
    }

    // 清理 errorInfo
    if (!(status & (WBVappStatusDownloadError | WBVappStatusInstallError | WBVappStatusResourceDownloadError | WBVappStatusResourceInstallError | WBVappStatusInitError))) {
        _errorInfo.errorType = WBVappStatusNone;
        _errorInfo.errorDomain = @"";
        _errorInfo.errorCode = 0;
        _errorInfo.errorMessage = @"";
    }

    [self setStatus:status];
}

- (void)setStatus:(WBVappStatus)status {
    if (_status == status) return;
    NSLog(@"vapp%@, status:%d -> %d", _name, (int)log2(_status), (int)log2(status));
    _status = status;
}

- (void)saveError:(WBVappStatus)errorType errorDomain:(NSString *)errorDomain errorCode:(NSInteger)errorCode errorMessage:(NSString *)errorMessage {
    if (_errorInfo.errorType == errorType && _errorInfo.errorCode == errorCode) { return;
    }
    _errorInfo.errorType = errorType;
    _errorInfo.errorDomain = errorDomain;
    _errorInfo.errorCode = errorCode;
    _errorInfo.errorMessage = errorMessage;
}


- (NSString *)literalStatus {
    switch(_status) {
        case WBVappStatusNone:
            return nil;
        case WBVappStatusWaitingDownload:
            return @"等待下载";
        case WBVappStatusDownloading:
            return @"下载中";
        case WBVappStatusDownloadError:
            return @"下载失败";
        case WBVappStatusDownloadInterrupted:
            return @"下载中断";
        case WBVappStatusDownloaded:
            return @"下载成功";
        case WBVappStatusWaitingInstall:
            return @"等待安装";
        case WBVappStatusInstalled:
            return nil;
        case WBVappStatusInstalling:
            return @"安装中";
        case WBVappStatusInstallError:
            return @"安装失败";
        case WBVappStatusInited:
            return nil;
        case WBVappStatusResourceWaitingDownload:
//            return @"等待更新";
        case WBVappStatusResourceDownloading:
        case WBVappStatusResourceDownloadInterrupted:
//            return @"更新中";
        case WBVappStatusResourceDownloadError:
//            return @"更新失败";
        default:
            return nil;
    }
}

- (NSString *)literalCompactStatus {
    switch(_status) {
        case WBVappStatusNone:
            return nil;
        case WBVappStatusWaitingDownload:
            return @"待下载";
        case WBVappStatusDownloading:
            return @"下载中";
        case WBVappStatusDownloadError:
            return @"请重试";
        case WBVappStatusDownloadInterrupted:
            return @"下载中";
        case WBVappStatusDownloaded:
            return @"已下载";
        case WBVappStatusWaitingInstall:
            return @"待安装";
        case WBVappStatusInstalled:
            return nil;
        case WBVappStatusInstalling:
            return @"安装中";
        case WBVappStatusInstallError:
            return @"请重试";
        case WBVappStatusInited:
            return nil;
        default:
            return nil;
    }
}

- (BOOL)needReinstall {
    switch (self.status) {
        case WBVappStatusResourceInstallError:
        case WBVappStatusInitError:
            return true;
        default:
            return false;
    }
}

- (BOOL)isLaunchable {
    if (self.isDealingWithResource) return true;
    switch (self.status) {
        case WBVappStatusInstalled:
        case WBVappStatusInited:
            return true;
        default:
            return false;
    }
}

- (BOOL)isDealingWithResource {
    switch (self.status) {
        case WBVappStatusResourceWaitingDownload:
        case WBVappStatusResourceDownloading:
        case WBVappStatusResourceDownloaded:
        case WBVappStatusResourceDownloadInterrupted:
        case WBVappStatusResourceDownloadError:
        case WBVappStatusResourceDownloadGiveUp:
        case WBVappStatusResourceInstalling:
        case WBVappStatusResourceInstalled:
            return true;
        default:
            return false;
    }
}

- (BOOL)isGetable {
    if (_dual == TRUE) {
        if (_status == WBVappStatusNone) {
            return TRUE;
        }
    }
    return FALSE;
}

- (BOOL)isDuable {
  return _dual == TRUE;
}

- (BOOL)isReserved {
    return _reserved;
}

- (BOOL)isDownload {
    return _isDownload;
}

- (void)addStatusObserver:(id)observer {
    NSKeyValueObservingOptions option =  NSKeyValueObservingOptionNew;
    [self addObserver:observer forKeyPath:@"status" options:option context:nil];
    [self addObserver:observer forKeyPath:@"dual" options:option context:nil];
    [self addObserver:observer forKeyPath:@"reserved" options:option context:nil];
    [self addObserver:observer forKeyPath:@"reserveCount" options:option context:nil];
    [self addObserver:observer forKeyPath:@"isDownload" options:option context:nil];
}

- (void)removeStatusObserver:(id)observer {
    [self removeObserver:observer forKeyPath:@"status"];
    [self removeObserver:observer forKeyPath:@"dual"];
    [self removeObserver:observer forKeyPath:@"reserved"];
    [self removeObserver:observer forKeyPath:@"reserveCount"];
    [self removeObserver:observer forKeyPath:@"isDownload"];
}

- (BOOL)isEqual:(id)object {
    if (![object isKindOfClass:[self class]]) return false;
    return self == object || [self.bundleId isEqual:[object bundleId]];
}

- (WBVAppUserInfo *)userInfo {
    if (!_userInfo) {
        _userInfo = [[WBVAppUserInfo alloc] init];
    }
    return _userInfo;
}

- (void)cleanCache {
    WBVAppUserInfo *userInfo = self.userInfo;
    BOOL couldClearCache = false;
    // cache cache with switch-case full through, non break
    switch (self.status) {
        case WBVappStatusWaitingDownload:
        case WBVappStatusDownloading:
        case WBVappStatusDownloaded:
        case WBVappStatusWaitingInstall:
        case WBVappStatusInstalling:
        case WBVappStatusResourceWaitingDownload:
        case WBVappStatusResourceDownloading:
        case WBVappStatusResourceDownloaded:
        case WBVappStatusResourceInstalling:
            break;// 以上几种情况都是不能删除安装、资源包的情况
        default:
        {
            couldClearCache = true;
            break;
        }
    }
    if(couldClearCache){
        [self removeCacheFileOrDirIfExist:userInfo.ipaZipPath];
        [self removeCacheFileOrDirIfExist:userInfo.resZipPath];
        [self removeCacheFileOrDirIfExist:userInfo.ipaUnzipPath];
        [self removeCacheFileOrDirIfExist:userInfo.resUnzipPath];
//        BOOL ipaZipResult = [self removeCacheFileOrDirIfExist:userInfo.ipaZipPath];
//        BOOL resZipResult = [self removeCacheFileOrDirIfExist:userInfo.resZipPath];
//        BOOL ipaUnZipResult = [self removeCacheFileOrDirIfExist:userInfo.ipaUnzipPath];
//        BOOL resUnZipResult = [self removeCacheFileOrDirIfExist:userInfo.resUnzipPath];
//        NSLog(@"4个结果分别是：%d,%d,%d,%d,",ipaZipResult,resZipResult,ipaUnZipResult,resUnZipResult);
        [SVProgressHUD showSuccessWithStatus:@"清除成功"];
    }else{
        [SVProgressHUD showErrorWithStatus:@"有资源正在下载或安装，请稍后再试。"];
    }
}

- (BOOL)removeCacheFileOrDirIfExist:(NSString *)itemPath {
    if (itemPath == nil) return false;
    if (![[NSFileManager defaultManager] fileExistsAtPath:itemPath isDirectory:nil]) return false;
    NSError *err = nil;
    BOOL success = [[NSFileManager defaultManager] removeItemAtPath:itemPath error:&err];
    NSParameterAssert(success ^ (err != nil));
    return err == nil;
}

@end

